    'The rhetorical questions in this passage function primarily to',
    'multiple_choice',
    '[{"id":"A","text":"establish a sense of intimacy and connection with the reader.","is_correct":true,"explanation":""},{"id":"B","text":"explain the speaker’s feelings and experiences.","is_correct":false,"explanation":""},{"id":"C","text":"highlight the importance of the speaker’s message.","is_correct":false,"explanation":""},{"id":"D","text":"suggest that the speaker is addressing a large audience.","is_correct":false,"explanation":""}]'::jsonb,
