    'multiple_choice',
    '[{"id":"A","text":"To show that the speaker is addressing a specific audience.","is_correct":false,"explanation":""},{"id":"B","text":"To create a sense of intimacy and connection with the reader.","is_correct":true,"explanation":""},{"id":"C","text":"To provide an example of the speaker’s style of writing.","is_correct":false,"explanation":""},{"id":"D","text":"To emphasize the speaker''s point of view.","is_correct":false,"explanation":""}]'::jsonb,
