    '[{"id":"A","text":"highlight the superficiality of the characters'' differences.","is_correct":false,"explanation":""},{"id":"B","text":"suggest that the characters'' similarities are more important than their differences.","is_correct":false,"explanation":""},{"id":"C","text":"emphasize the importance of the characters'' shared history.","is_correct":false,"explanation":""},{"id":"D","text":"show that the characters are not as similar as they first appear.","is_correct":true,"explanation":""}]'::jsonb,
    'D',
